### Pricing Configuration
```typescript
interface IPFSPricingConfig {
  // Regular accounts
  regularMinCost: bigint;           // 1 DEM
  regularBytesPerUnit: number;      // 100 * 1024 * 1024 (100MB)
  regularCostPerUnit: bigint;       // 1 DEM

  // Genesis accounts  
  genesisFreeBytes: number;         // 1 * 1024 * 1024 * 1024 (1GB)
  genesisBytesPerUnit: number;      // 1 * 1024 * 1024 * 1024 (1GB)
  genesisCostPerUnit: bigint;       // 1 DEM

  // Fee distribution (MVP: 100% to host)
  hostShare: number;                // 100 (percentage)
  treasuryShare: number;            // 0 (percentage)
  consensusShare: number;           // 0 (percentage)
}
```

### Pricing Functions
```typescript
function calculatePinCost(
  fileSizeBytes: number, 
  isGenesisAccount: boolean,
  usedFreeBytes: number
): bigint {
  if (isGenesisAccount) {
    const freeRemaining = Math.max(0, config.genesisFreeBytes - usedFreeBytes);
    if (fileSizeBytes <= freeRemaining) return 0n;
    const chargeableBytes = fileSizeBytes - freeRemaining;
    return BigInt(Math.ceil(chargeableBytes / config.genesisBytesPerUnit));
  }

  // Regular account
  const units = Math.ceil(fileSizeBytes / config.regularBytesPerUnit);
  return BigInt(Math.max(1, units)) * config.regularCostPerUnit;
}
```

